INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Lecture: “Why We Need Scores: From the Sumerians to Graphic Notation”', 'Starting from early notation systems, he traced how scores evolved over time and why they matter: not just technically, but culturally. The lecture helped position notation as something that shapes how we think about music itself.', '2026-07-23', '13:00:00', '14:00:00', 'Lecture', 'Online', 100, 'Alexey Munipov', 'active');
