INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Workshop: “Audible Spaces”', 'This workshop explored spatial hearing and its application in sound composition. Through theory, listening exercises, and hands-on work with SPASM for Live, participants created headphone-based sound environments, using movement and tracking to navigate sound in space. No prior experience was required.', '2026-07-23', '20:00:00', '22:00:00', 'Lecture', 'Library (ground floor)', 100, 'Sebastian Frisch', 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Breakfast', NULL, '2026-07-24', '09:00:00', '10:00:00', 'Meal', '26 Vazgen Sargsyan St', NULL, NULL, 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Workshop: “Introduction to Ableton”', 'Every day workshops were at 9:30AM and were covering music production basics, live performance setups, and ways to structure sound digitally.', '2026-07-24', '10:00:00', '10:30:00', 'Workshop', 'Shushiki Sound Room', 100, 'Andriesh Gandrabur', 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('General Meeting', NULL, '2026-07-24', '10:30:00', '11:00:00', 'Info Session', 'Concert Hall (second floor)', NULL, NULL, 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Workshop: Intro to Set Design, Forms, Materials', NULL, '2026-07-24', '11:00:00', '12:00:00', 'Workshop', 'Online', 100, 'Karina Malik, Yuriy Avdeev', 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Lecture: “What is Musical Performance”', 'This session questioned what performance actually is: moving beyond execution of a score towards presence, interpretation, and the relationship between body, sound, and space.', '2026-07-24', '11:00:00', '12:00:00', 'Lecture', 'Online', 100, 'Vladislav Tarnopolski', 'active');
INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Project Time', NULL, '2026-07-24', '12:00:00', '14:30:00', 'Work Session', 'Department Zone', NULL, NULL, 'active');
