INSERT INTO events (title, description, date, start_time, end_time, category, location, capacity, speakers, status) VALUES ('Lecture: “Introduction to Compositional Strategies of Notation and Scores”', 'Spoke about notation as something fluid: not only a way to fix music, but a way to propose it. The lecture focused on open scores, graphic notation, and systems where performers become co-authors.', '2026-07-24', '16:00:00', '17:00:00', 'Lecture', 'Online', 100, 'Vladimir Gorlinsky', 'active');
