-- Notations bot — D1 schema + seed
PRAGMA foreign_keys = ON;

CREATE TABLE IF NOT EXISTS participants (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  artistic_name TEXT,
  photo_url TEXT,
  role TEXT,
  projects TEXT,
  country TEXT,
  social_media TEXT,
  telegram TEXT,
  telegram_norm TEXT,
  email TEXT,
  project TEXT,
  discipline TEXT,
  tools TEXT,
  skill_set TEXT,
  linked_telegram_id INTEGER UNIQUE
);

CREATE TABLE IF NOT EXISTS users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  telegram_id INTEGER NOT NULL UNIQUE,
  username TEXT,
  first_name TEXT,
  participant_id INTEGER REFERENCES participants(id),
  reg_status TEXT NOT NULL DEFAULT 'new'
    CHECK (reg_status IN ('new', 'awaiting_name', 'registered')),
  is_admin INTEGER NOT NULL DEFAULT 0,
  state TEXT,
  state_data TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS admins (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  username TEXT NOT NULL,
  username_norm TEXT NOT NULL UNIQUE,
  telegram_id INTEGER UNIQUE,
  is_primary INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title TEXT NOT NULL,
  description TEXT,
  date TEXT NOT NULL,
  start_time TEXT NOT NULL,
  end_time TEXT,
  category TEXT,
  location TEXT,
  capacity INTEGER,
  speakers TEXT,
  status TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('active', 'cancelled')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS registrations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  event_id INTEGER NOT NULL REFERENCES events(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'registered'
    CHECK (status IN ('registered', 'cancelled')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (user_id, event_id)
);

CREATE TABLE IF NOT EXISTS connects (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  from_user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  to_participant_id INTEGER NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
  filters_json TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS circle_campaigns (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  prompt TEXT NOT NULL,
  audience_type TEXT NOT NULL,
  audience_json TEXT,
  created_by INTEGER,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS circle_targets (
  campaign_id INTEGER NOT NULL REFERENCES circle_campaigns(id) ON DELETE CASCADE,
  user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'done')),
  reminded_at TEXT,
  PRIMARY KEY (campaign_id, user_id)
);

CREATE TABLE IF NOT EXISTS circle_responses (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  campaign_id INTEGER NOT NULL REFERENCES circle_campaigns(id) ON DELETE CASCADE,
  user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  file_id TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE (campaign_id, user_id)
);

CREATE TABLE IF NOT EXISTS broadcasts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  created_by INTEGER,
  body_text TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft', 'sending', 'sent')),
  recipient_count INTEGER DEFAULT 0,
  idempotency_key TEXT UNIQUE,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  sent_at TEXT
);

CREATE TABLE IF NOT EXISTS user_navigation (
  user_id INTEGER PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE,
  stack TEXT NOT NULL DEFAULT '[]',
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE INDEX IF NOT EXISTS idx_participants_tg ON participants (telegram_norm);
CREATE INDEX IF NOT EXISTS idx_events_date ON events (date, start_time);
CREATE INDEX IF NOT EXISTS idx_reg_user ON registrations (user_id, status);
CREATE INDEX IF NOT EXISTS idx_reg_event ON registrations (event_id, status);
CREATE INDEX IF NOT EXISTS idx_users_participant ON users (participant_id);


PRAGMA foreign_keys=OFF;
DELETE FROM circle_responses;
DELETE FROM circle_targets;
DELETE FROM circle_campaigns;
DELETE FROM connects;
DELETE FROM broadcasts;
DELETE FROM registrations;
DELETE FROM events;
DELETE FROM participants;
DELETE FROM admins;
DELETE FROM sqlite_sequence WHERE name IN (
  'events','participants','admins','circle_campaigns','circle_responses','broadcasts','connects','registrations'
);
PRAGMA foreign_keys=ON;

-- Admins are unlocked via /admin + password (no seed row needed)

